	var generated *string
	mustChange := false
	if input.PasswordMode == model.PasswordModeAuto {
		t, err := auth.GenerateTempPassword()
		if err != nil {
			return nil, err
		}
		plain, generated, mustChange = t, &t, true
	} else {
		if input.CustomPassword == nil || *input.CustomPassword == "" {
			return nil, gqlerror.Errorf("customPassword is required when passwordMode is CUSTOM")
		}
		plain = *input.CustomPassword
	}
	hash, err := auth.HashPassword(plain)
	if err != nil {
		return nil, err
	}
	tenantID, err := r.resolveUserWriteTenant(ctx, nil, role)
	if err != nil {
		return nil, err
	}
	enabled := input.Enabled == nil || *input.Enabled
