// AssignUsersToRole sets the role of multiple users (skipping cross-tenant ones),
// revoking each affected user's sessions.
func (r *mutationResolver) AssignUsersToRole(ctx context.Context, input model.AssignUsersToRoleInput) (*model.AssignUsersToRolePayload, error) {
	if _, _, ok := builtinRole(input.RoleID); !ok {
		return nil, gqlerror.Errorf("unknown role: %s", input.RoleID)
	}
	newRole := model.RoleName(input.RoleID)
	cu := auth.FromContext(ctx)
	if cu != nil && cu.Role == auth.RoleTenantAdmin &&
		(newRole == model.RoleNameAdmin || newRole == model.RoleNameTenantAdmin) {
		return nil, gqlerror.Errorf("forbidden: tenant-admin cannot grant admin roles")
	}
	entRole := user.Role(gqlRoleToEnt(newRole))
	assigned := 0
	for _, uidStr := range input.UserIds {
		uid, err := uuid.Parse(uidStr)
		if err != nil {
			continue
		}
		if err := r.assertUserInCallerTenant(ctx, uid); err != nil {
			continue // skip cross-tenant / missing
		}
		if err := r.Ent.User.UpdateOneID(uid).SetRole(entRole).Exec(ctx); err != nil {
			continue
		}
		_ = r.Sessions.DeleteByUser(uid.String())
		assigned++
	}
	r.audit(ctx, "user.assign_role", "role", input.RoleID, true, actorID(cu))
	cnt, err := r.roleUserCount(ctx, input.RoleID)
	if err != nil {
		return nil, err
	}
	return &model.AssignUsersToRolePayload{Role: roleEntity(input.RoleID, cnt), AssignedCount: assigned}, nil
}

// Users lists users as a filtered/sorted/paged connection (用户与权限页). Tenant
// scoped. connectionStatus is derived per row from live sessions.
func (r *queryResolver) Users(ctx context.Context, filter *model.UserFilter, pagination *model.Pagination, sort *model.UserSort) (*model.UserConnection, error) {
	base := r.Ent.User.Query()
	if d := tenantScopeFor(ctx); d.apply {
		if d.denyAll {
			base = base.Where(user.IDEQ(uuid.Nil))
		} else {
			base = base.Where(user.TenantID(d.tenant))
		}
	}
	if filter != nil {
		if v := derefString(filter.UsernameKeyword); v != "" {
			base = base.Where(user.UsernameContainsFold(v))
		}
		if v := derefString(filter.EmailKeyword); v != "" {
			base = base.Where(user.EmailContainsFold(v))
		}
		if v := derefString(filter.RoleKeyword); v != "" {
			base = base.Where(user.RoleIn(matchRoleKeyword(v)...)) // empty → matches nothing
		}
		if filter.RoleID != nil && *filter.RoleID != "" {
			base = base.Where(user.RoleEQ(user.Role(gqlRoleToEnt(model.RoleName(*filter.RoleID)))))
		}
		// statusKeyword (ONLINE/OFFLINE) is derived from live sessions, not a column,
		// so it is not applied as a SQL filter (would break pagination counts).
	}
	total, err := base.Clone().Count(ctx)
	if err != nil {
		return nil, err
	}
	page, pageSize := 1, 20
	if pagination != nil {
		if pagination.Page > 0 {
			page = pagination.Page
		}
		if pagination.PageSize > 0 {
			pageSize = pagination.PageSize
		}
	}
	us, err := applyUserSort(base.Clone(), sort).Offset((page - 1) * pageSize).Limit(pageSize).All(ctx)
	if err != nil {
		return nil, err
	}
	nodes := make([]model.AccountUser, 0, len(us))
	for _, u := range us {
		online, _ := r.Sessions.ActiveByUser(u.ID.String())
		nodes = append(nodes, *toAccountUser(u, online))
	}
	totalPages := (total + pageSize - 1) / pageSize
	return &model.UserConnection{
		Nodes:      nodes,
		TotalCount: total,
		PageInfo:   &model.PageInfo{Page: page, PageSize: pageSize, TotalPages: totalPages},
	}, nil
}

// Roles lists the built-in assignable roles as entities, each with its user count.
func (r *queryResolver) Roles(ctx context.Context, pagination *model.Pagination) (*model.RoleConnection, error) {
	nodes := make([]model.Role, 0, len(builtinRoles))
	for _, br := range builtinRoles {
		cnt, err := r.roleUserCount(ctx, br.id)
		if err != nil {
			return nil, err
		}
		nodes = append(nodes, *roleEntity(br.id, cnt))
	}
	total := len(nodes)
	return &model.RoleConnection{
		Nodes:      nodes,
		TotalCount: total,
		PageInfo:   &model.PageInfo{Page: 1, PageSize: total, TotalPages: 1},
	}, nil
}

// Role returns one built-in role by id, or nil if unknown.
func (r *queryResolver) Role(ctx context.Context, id string) (*model.Role, error) {
	if _, _, ok := builtinRole(id); !ok {
		return nil, nil
	}
	cnt, err := r.roleUserCount(ctx, id)
	if err != nil {
		return nil, err
	}
	return roleEntity(id, cnt), nil
}

// UserExists is the debounced dedupe check for the create-user form (global —
// username/email uniqueness is not tenant-scoped).
func (r *queryResolver) UserExists(ctx context.Context, username *string, email *string) (bool, error) {
	un, em := derefString(username), derefString(email)
	if un == "" && em == "" {
		return false, nil
	}
	q := r.Ent.User.Query()
	switch {
	case un != "" && em != "":
		q = q.Where(user.Or(user.Username(un), user.Email(em)))
	case un != "":
		q = q.Where(user.Username(un))
	default:
		q = q.Where(user.Email(em))
	}
	return q.Exist(ctx)
}
